update dda_programmes
set contenu = jsonb_set(
  contenu,
  '{sections}',
  (
    select jsonb_agg(
      case when m.val is not null
      then jsonb_set(elem, '{questions}', (elem->'questions') || m.val)
      else elem end
    )
    from jsonb_array_elements(contenu->'sections') elem
    left join jsonb_each($map${"evaluation_a": [{"q": "Combien de maillons distincts comporte la chaîne de valeur du risque professionnel décrite en A.1 ?", "opts": ["2 (assureur, client)", "4 (assureur, grossiste, courtier, client)", "6"], "correct": 1}, {"q": "Le devoir de conseil de S@FE relève-t-il d'une obligation de moyens ou de résultat ?", "opts": ["D'une obligation de résultat, comme l'indemnisation", "D'une obligation de moyens, distincte de l'indemnisation", "Ni l'une ni l'autre"], "correct": 1}, {"q": "Quelle qualification IAS détient Sébastien en tant que Président de S@FE ?", "opts": ["Niveau 1 (150h)", "Niveau 2 (mandataire)", "Niveau 3 (distribution accessoire)"], "correct": 0}, {"q": "L'honorabilité d'un intermédiaire s'apprécie notamment au regard de :", "opts": ["Son ancienneté dans l'entreprise", "Le bulletin n°2 du casier judiciaire", "Son chiffre d'affaires personnel"], "correct": 1}, {"q": "Pour un contrat Cyber, l'IPID doit permettre de distinguer notamment :", "opts": ["La garantie de première ligne et la garantie de troisième ligne", "Le DIC et la FSI", "Le tarif mensuel et annuel uniquement"], "correct": 0}, {"q": "Un dirigeant qui résilie un contrat Flotte en cours d'année, sur le modèle de la loi Hamon pour un particulier, risque de découvrir :", "opts": ["Que la résiliation est immédiate comme pour un particulier", "Un préavis contractuel de plusieurs mois", "Qu'aucune règle ne s'applique"], "correct": 1}, {"q": "Un dirigeant ou un DAF est-il présumé maîtriser les spécificités techniques de l'assurance des risques professionnels ?", "opts": ["Oui, systématiquement", "Non, il ne faut jamais le présumer", "Oui, s'il gère une grande entreprise"], "correct": 1}, {"q": "Quel type de structure appelle une vigilance LCB-FT renforcée pour les dossiers RC Décennale ?", "opts": ["Les montages de co-traitance et sous-traitance en cascade", "Les entreprises individuelles simples", "Les artisans mono-actifs"], "correct": 0}, {"q": "Une société de 2 salariés sollicitant une flotte de 40 véhicules professionnels sans justification constitue :", "opts": ["Une situation parfaitement normale", "Un signal d'alerte à approfondir", "Une preuve certaine de fraude"], "correct": 1}, {"q": "Le RGPD est-il un sujet uniquement interne pour Émilie, ou aussi un sujet métier direct ?", "opts": ["Uniquement interne (données de S@FE)", "Aussi un sujet métier direct dès le conseil sur un contrat Cyber", "Il ne concerne pas son activité"], "correct": 1}, {"q": "En cas de sinistre Cyber avec fuite de données, quel est le rôle d'Émilie vis-à-vis de la notification CNIL ?", "opts": ["Qualifier juridiquement l'obligation à la place du client", "Orienter et rappeler l'existence et l'urgence de l'obligation", "Ignorer ce sujet, hors de son périmètre"], "correct": 1}, {"q": "Sur un contrat Cyber, l'urgence de la réponse à incident impose des délais de déclaration :", "opts": ["Identiques à un sinistre classique", "Souvent plus courts que sur des contrats classiques", "Sans limite de temps"], "correct": 1}, {"q": "Un client TPE en RC Décennale qui décroche un premier marché à l'export hors UE doit être traité par :", "opts": ["Un simple avenant de tarification", "Une nouvelle analyse de risque complète", "Aucune action, le contrat reste valable tel quel"], "correct": 1}, {"q": "Dans la gouvernance produit DDA, qui porte le devoir de conseil vis-à-vis du client final chez S@FE ?", "opts": ["L'assureur partenaire (Hiscox, etc.)", "S@FE Assurances elle-même", "Le grossiste (Dattak, AMI3F)"], "correct": 1}, {"q": "Émilie peut-elle se retrancher derrière « c'est le contrat de l'assureur » pour éluder son devoir de conseil ?", "opts": ["Oui, si le produit vient d'un partenaire", "Non, jamais", "Oui, uniquement pour la RC Décennale"], "correct": 1}, {"q": "Quel est l'un des paramètres structurants de l'analyse objective du profil de risque d'une entreprise (Unité A.3) ?", "opts": ["Le secteur d'activité identifié par le code NAF", "La couleur du logo de l'entreprise", "Le jour de la semaine du rendez-vous"], "correct": 0}, {"q": "Pour une entreprise du BTP réalisant des travaux de charpente, la fiche de conseil RC Décennale doit notamment justifier :", "opts": ["La nature obligatoire de la garantie pour le gros œuvre au sens de la loi Spinetta", "Le nombre de congés payés des salariés", "La couleur des véhicules de chantier"], "correct": 0}, {"q": "L'assurance dommages-ouvrage est souscrite par :", "opts": ["Le constructeur", "Le maître d'ouvrage", "L'assureur décennal"], "correct": 1}, {"q": "Le cumul des fonctions de Président et de DPO chez Sébastien nécessite :", "opts": ["Aucune mesure particulière", "Des mesures compensatoires documentées", "L'abandon de l'une des deux fonctions"], "correct": 1}, {"q": "Dans un contexte B2B, les interlocuteurs d'une réclamation peuvent varier selon le sujet. Qui intervient typiquement sur un désaccord de facturation ?", "opts": ["Le DAF", "Le RSSI", "Le médiateur de l'assurance directement"], "correct": 0}]}$map$::jsonb) m(key, val) on m.key = elem->>'id'
  )
)
where id = '005e7570-dd00-41cd-952b-5b8d5f158090';
